import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Other/auto-tagging.md","filePath":"ta/Other/auto-tagging.md","lastUpdated":1781962217000}'),o={name:"ta/Other/auto-tagging.md"};function n(d,a,g,c,p,r){return i(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging இங்கு configure செய்யப்படுகிறது:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>இது image tags-ஐ தானாக உருவாக்கும். search, random image filtering, public gallery filtering, age-rating access control ஆகியவற்றுக்கு tags உதவும்.</p><h2 id="auto-tagging-என்ன-செய்ய-முடியும்" tabindex="-1">Auto Tagging என்ன செய்ய முடியும் <a class="header-anchor" href="#auto-tagging-என்ன-செய்ய-முடியும்" aria-label="Permalink to &quot;Auto Tagging என்ன செய்ய முடியும்&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>content tags உருவாக்குதல்</td><td>people, scenes, objects, art style போன்ற visual content tags சேர்க்கும்.</td></tr><tr><td>character tags உருவாக்குதல்</td><td>anime images மற்றும் illustrations-க்கு useful.</td></tr><tr><td>orientation tags சேர்த்தல்</td><td><code>landscape</code>, <code>portrait</code>, அல்லது <code>square</code> சேர்க்கும்.</td></tr><tr><td>image rating சேர்த்தல்</td><td>general, sensitive, questionable, explicit content-க்கு <code>G/S/Q/E</code> rating results சேமிக்கும்.</td></tr><tr><td>upload-ல் auto-tag</td><td>புதிய images upload ஆனவுடன் tagging flow-க்கு தானாக செல்லும்.</td></tr><tr><td>Batch tagging</td><td>அனைத்து folders அல்லது selected folders-ல் உள்ள பழைய images-க்கு tags சேர்க்கும்.</td></tr></tbody></table><h2 id="முதலில்-தேவையானது" tabindex="-1">முதலில் தேவையானது <a class="header-anchor" href="#முதலில்-தேவையானது" aria-label="Permalink to &quot;முதலில் தேவையானது&quot;">​</a></h2><p>குறைந்தது ஒரு accessible Hugging Face Space URL தயார் செய்யவும்.</p><p>recommended முறையாக SmilingWolf-ன் <code>wd-tagger</code> Space-ஐ உங்கள் Hugging Face account-க்கு duplicate செய்யலாம்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>public Space temporary testing-க்கு பயன்படுத்தலாம். ஆனால் public Spaces பல users share செய்வதால் queue, slow response, அல்லது temporary unavailable நிலை வரலாம். உங்கள் account-ல் duplicated Space long-term auto tagging-க்கு நிலையாக இருக்கும்.</p><h2 id="smilingwolf-space-duplicate-செய்யவும்" tabindex="-1">SmilingWolf Space Duplicate செய்யவும் <a class="header-anchor" href="#smilingwolf-space-duplicate-செய்யவும்" aria-label="Permalink to &quot;SmilingWolf Space Duplicate செய்யவும்&quot;">​</a></h2><ol><li>Hugging Face-ல் sign in செய்யவும்.</li><li><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code> திறக்கவும்.</li></ol><p><img src="'+t+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>மேல் வலது three-dot menu கிளிக் செய்யவும்.</li><li><code>Duplicate this Space</code> தேர்வு செய்யவும்.</li><li>default Space name வைத்திருக்கலாம் அல்லது <code>wd-tagger</code> போன்ற பெயர் தரலாம்.</li><li>visibility-ஐ <code>Public</code> ஆக அமைக்கவும். Public Spaces-ஐ ImgBed call செய்வது எளிது.</li><li>ஆரம்பத்தில் default free hardware வைத்திருக்கவும். queue பிரச்சினை தெளிவாக இருந்தால் பின்னர் upgrade செய்யவும்.</li><li>Space create செய்து build முடியும் வரை காத்திருக்கவும்.</li></ol><p>build முடிந்த பிறகு உங்கள் Space page திறக்கவும். URL பொதுவாக:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>browser URL copy செய்து ImgBed <code>Space URLs</code>-ல் paste செய்யவும்.</p><h2 id="multiple-space-urls-நிரப்புதல்" tabindex="-1">Multiple Space URLs நிரப்புதல் <a class="header-anchor" href="#multiple-space-urls-நிரப்புதல்" aria-label="Permalink to &quot;Multiple Space URLs நிரப்புதல்&quot;">​</a></h2><p>ஒரு line-க்கு ஒரு Space URL.</p><table tabindex="0"><thead><tr><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf public Space. temporary testing-க்கு.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>copied Space page URL.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>உங்கள் duplicated Space page URL.</td></tr></tbody></table><p>பல URLs தரலாம். ImgBed பல Spaces-ஐ சேர்த்து பயன்படுத்தும்; speed மேம்படலாம்.</p><p>ஒரு Space unavailable என்றாலும் மற்றவை processing தொடரலாம்.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>தயார் செய்த Space URLs நிரப்பவும். குறைந்தது ஒன்று.</td></tr><tr><td>Target folder</td><td>அனைத்து folders-க்கு காலியாக விடவும். specific directory என்றால் மட்டும் folder தேர்வு செய்யவும்.</td></tr><tr><td>Recognition model</td><td>default <code>wd-swinv2-tagger-v3</code> வைத்திருக்கவும்.</td></tr><tr><td>General tag threshold</td><td>default பெரும்பாலான images-க்கு பொருந்தும். குறைந்த value அதிக tags; அதிக value குறைந்த tags.</td></tr><tr><td>Character tag threshold</td><td>default conservative; தவறான character tags குறைக்க உதவும்.</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>ஆரம்பத்தில் off. model தானாக tag count தீர்மானிக்க வேண்டும் என்றால் on.</td></tr><tr><td>Auto-tag on upload</td><td>புதிய uploaded images தானாக tag பெற வேண்டும் என்றால் on.</td></tr><tr><td>Start tagging</td><td>பழைய images-க்கு manual batch-tagging.</td></tr></tbody></table><h2 id="recommended-starting-values" tabindex="-1">Recommended Starting Values <a class="header-anchor" href="#recommended-starting-values" aria-label="Permalink to &quot;Recommended Starting Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommended Value</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>ஆரம்பத்தில் Off</td></tr><tr><td>Auto-tag on upload</td><td>தேவைப்பட்டால் Enable</td></tr></tbody></table><p>tags அதிகமாக இருந்தால் general threshold சிறிது உயர்த்தவும்.</p><p>tags குறைவாக இருந்தால் general threshold சிறிது குறைக்கவும்.</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li><code>Space URLs</code> நிரப்பவும்.</li><li>target folder தேர்வு செய்யவும்.</li><li>start tagging கிளிக் செய்யவும்.</li><li>progress முடியும் வரை காத்திருக்கவும்.</li></ol><p>target folder empty என்றால் ImgBed அனைத்து folders process செய்யும்.</p><p>Batch tagging பழைய images-க்கு சிறந்தது. புதிய images-க்கு auto-tag on upload enable செய்தால் ஒவ்வொரு முறையும் manual run தேவையில்லை.</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>auto-tag on upload enabled ஆன பிறகு புதிய uploaded images configured <code>Space URLs</code>-ஐ தானாக call செய்யும்.</p><p>long-term use-க்கு இது பொருத்தம்.</p><p>Space queue-ல் இருந்தாலும் upload முதலில் finish ஆகலாம்; tagging பின்னர் தொடரும்.</p><h2 id="எந்த-images-process-ஆகும்" tabindex="-1">எந்த Images Process ஆகும் <a class="header-anchor" href="#எந்த-images-process-ஆகும்" aria-label="Permalink to &quot;எந்த Images Process ஆகும்&quot;">​</a></h2><p>Auto tagging முதன்மையாக image files process செய்கிறது.</p><p>tags, orientation, rating, width, height ஏற்கனவே complete உள்ள images skip செய்யப்படும். unnecessary Space calls தவிர்க்கப்படும்.</p><p>சாத்தியமானபோது ImgBed missing information மட்டும் நிரப்பும். உதாரணமாக orientation மட்டும் missing என்றால் full content tag flow call செய்யாமல் orientation சேர்க்க முயலும்.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="என்-space-ஐ-ஏன்-duplicate-செய்ய-வேண்டும்" tabindex="-1">என் Space-ஐ ஏன் Duplicate செய்ய வேண்டும்? <a class="header-anchor" href="#என்-space-ஐ-ஏன்-duplicate-செய்ய-வேண்டும்" aria-label="Permalink to &quot;என் Space-ஐ ஏன் Duplicate செய்ய வேண்டும்?&quot;">​</a></h3><p>Public Spaces பல users-ஆல் share செய்யப்படும். உங்கள் duplicated Space பெரும்பாலும் உங்கள் ImgBed site மட்டும் பயன்படுத்தும்; எனவே வேகமாகவும் நம்பகமாகவும் இருக்கும்.</p><h3 id="space-தொடர்ந்து-starting-up-ஆகிறது" tabindex="-1">Space தொடர்ந்து Starting Up ஆகிறது <a class="header-anchor" href="#space-தொடர்ந்து-starting-up-ஆகிறது" aria-label="Permalink to &quot;Space தொடர்ந்து Starting Up ஆகிறது&quot;">​</a></h3><p>முதல் creation பிறகு அல்லது நீண்ட idle period பிறகு Space start ஆக நேரம் எடுக்கலாம்.</p><p>முதலில் உங்கள் Space page திறக்கவும். image recognize செய்ய ஆரம்பித்த பிறகு ImgBed-க்கு திரும்பி tagging தொடங்கவும்.</p><h3 id="space-url-எப்படி-copy-செய்வது" tabindex="-1">Space URL எப்படி Copy செய்வது? <a class="header-anchor" href="#space-url-எப்படி-copy-செய்வது" aria-label="Permalink to &quot;Space URL எப்படி Copy செய்வது?&quot;">​</a></h3><p>Hugging Face Space page திறந்து browser address copy செய்யவும்.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="multiple-spaces-சேர்க்கலாமா" tabindex="-1">Multiple Spaces சேர்க்கலாமா? <a class="header-anchor" href="#multiple-spaces-சேர்க்கலாமா" aria-label="Permalink to &quot;Multiple Spaces சேர்க்கலாமா?&quot;">​</a></h3><p>ஆம். ஒரு line-க்கு ஒரு Space URL.</p><p>பல Spaces images-ஐ சேர்ந்து process செய்யும்; images அதிகமானபோது பயனுள்ளது.</p><h3 id="tags-ஏன்-english-ல்" tabindex="-1">Tags ஏன் English-ல்? <a class="header-anchor" href="#tags-ஏன்-english-ல்" aria-label="Permalink to &quot;Tags ஏன் English-ல்?&quot;">​</a></h3><p>SmilingWolf models English tags output செய்கின்றன. இது expected.</p><p>tags search, filtering, random image API, public gallery filters ஆகியவற்றுக்கு பயன்படுத்தப்படும்.</p><h3 id="rating-tags-எதற்கு" tabindex="-1">Rating Tags எதற்கு? <a class="header-anchor" href="#rating-tags-எதற்கு" aria-label="Permalink to &quot;Rating Tags எதற்கு?&quot;">​</a></h3><p>rating results Security Settings-ல் உள்ள access mode உடன் இயங்கும்.</p><p>visitor access age rating மூலம் limited என்றால் public browsing மற்றும் random image features அந்த rules படி images filter செய்யும்.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hugging Face-ல் sign in</span></span>
<span class="line"><span>-&gt; SmilingWolf/wd-tagger திறக்கவும்</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Space build முடியும் வரை காத்திருக்கவும்</span></span>
<span class="line"><span>-&gt; உங்கள் Space URL copy செய்யவும்</span></span>
<span class="line"><span>-&gt; ImgBed-ல் Space URLs நிரப்பவும்</span></span>
<span class="line"><span>-&gt; model மற்றும் thresholds தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; Start tagging அல்லது auto-tag on upload enable செய்யவும்</span></span></code></pre></div>`,61)])])}const b=e(o,[["render",n]]);export{m as __pageData,b as default};
